       OR NEW.reference_number ~* '^BL-[0-9]{4}-[0-9]{2}-[0-9]{2}-'
     ) THEN
    NEW.reference_number := gc_next_sales_document_reference(NEW.store_id, 'DELIVERY_NOTE', 'BL', COALESCE(NEW.document_date, CURRENT_DATE));
  END IF;

